class Solution {
public:
    bool reorderedPowerOf2(int n) {
        string str = to_string(n);
        sort(str.begin(), str.end());
        for (int i = 0; i < 31; ++i) {
            long long power = 1LL << i;
            string powStr = to_string(power);
            sort(powStr.begin(), powStr.end());
            if (str == powStr) return true;
        }
        return false;
    }
};
